  | 'pricing_plan_click'
  | 'upgrade_cta_click'
  | 'nav_cta_click'
  | 'tool_used';

declare global {
  interface Window {
    dataLayer?: Array<Record<string, unknown>>;
  }
}

// ─── Tool Types ───────────────────────────────────────────────────────────────
type ToolId =
  | 'quote'
  | 'dayrate'
  | 'leadvalue'
  | 'markup'
  | 'timeestimate'
  | 'fuelcost'
  | 'invoice'
  | 'profit'
  | 'cashflow'
  | 'vatcheck';

type JobUrgency = 'today' | 'this_week' | 'planned';

type LeadJob = {
  title: string;
  trade: string;
  location: string;
  estimatedValue: number;
  urgency: JobUrgency;
  source?: string;
  sourceConfidence?: number;
  whyMatched?: string;
};

